// Parse Pararius.nl HTML listings
// Pararius uses server-side rendered HTML with stable CSS classes
const items = $input.all();
const results = [];

for (const item of items) {
  const html = item.json.data || '';

  if (!html || html.length < 500) {
    continue; // Skip empty/error responses
  }

  // Split HTML by listing search items
  // Pararius uses <section> or <li> with class containing 'search-list__item--listing'
  const listingBlocks = html.split(/(?=<(?:section|li|div)[^>]*listing-search-item[^>]*>)/);

  for (const block of listingBlocks) {
    // Extract the listing URL
    const urlMatch = block.match(/href="(\/huurwoning[^"]+)"/i)
                  || block.match(/href="(\/appartement[^"]+)"/i)
                  || block.match(/href="(\/huurwoningen-detail[^"]+)"/i);

    // Extract the title/address
    const titleMatch = block.match(/listing-search-item__title[^>]*>\s*([^<]+)/)
                     || block.match(/class="[^"]*title[^"]*"[^>]*>\s*([^<]+)/);

    // Extract the price
    const priceMatch = block.match(/listing-search-item__price[^>]*>\s*([^<]+)/)
                     || block.match(/price[^>]*>\s*(?:€|&euro;)\s*([\d.,]+)/);

    // Extract features (rooms, area)
    const roomsMatch = block.match(/(\d+)\s*(?:kamer|slaapkamer|bedroom)/i);
    const areaMatch = block.match(/(\d+)\s*m[²2]/);

    if (urlMatch && titleMatch) {
      const priceText = priceMatch ? priceMatch[1].trim() : 'Prijs onbekend';
      // Parse numeric price: handle "€ 1.250" or "1250" or "€1,250"
      const priceClean = priceText.replace(/[^\d.,]/g, '').replace(/\./g, '').replace(',', '.');
      const priceNum = parseInt(priceClean) || 0;

      // Only include listings in our price range
      if (priceNum === 0 || (priceNum >= 900 && priceNum <= 1600)) {
        results.push({
          json: {
            bron: 'Pararius',
            titel: titleMatch[1].trim(),
            prijs: priceText.includes('€') ? priceText : '€ ' + priceText,
            prijsNumeriek: priceNum,
            kamers: roomsMatch ? parseInt(roomsMatch[1]) : null,
            oppervlakte: areaMatch ? areaMatch[1] + ' m²' : null,
            url: 'https://www.pararius.nl' + urlMatch[1],
            scraped: new Date().toISOString()
          }
        });
      }
    }
  }
}

if (results.length === 0) {
  return [{ json: { bron: 'Pararius', fout: 'Geen woningen gevonden of geblokkeerd door anti-scraping', scraped: new Date().toISOString() } }];
}

// Deduplicate by URL
const seen = new Set();
const unique = results.filter(r => {
  if (seen.has(r.json.url)) return false;
  seen.add(r.json.url);
  return true;
});

return unique;

// Parse Huurwoningen.nl HTML listings
// Huurwoningen.nl may block automated requests (403)
// If the page loads, listings are in server-rendered HTML
const html = $input.first().json.data || '';
const results = [];

if (!html || html.length < 500 || html.includes('403') || html.includes('Access Denied')) {
  return [{ json: { bron: 'Huurwoningen.nl', fout: 'Geblokkeerd door website (403). Probeer met proxy of browser-extensie.', scraped: new Date().toISOString() } }];
}

// Huurwoningen.nl listing blocks
// They use classes like 'listing' or 'object-list__item' for listing cards
const listingBlocks = html.split(/(?=<(?:div|article|li)[^>]*(?:listing|object-list__item|search-result)[^>]*>)/i);

for (const block of listingBlocks) {
  // Try multiple selector patterns for URL
  const urlMatch = block.match(/href="((?:https?:\/\/www\.huurwoningen\.nl)?\/[^"]*enschede[^"]*)"/i)
                || block.match(/href="(\/woning[^"]+)"/i)
                || block.match(/href="(\/appartement[^"]+)"/i);

  // Title / address
  const titleMatch = block.match(/class="[^"]*(?:title|address|street)[^"]*"[^>]*>\s*([^<]+)/i)
                   || block.match(/<h[23][^>]*>\s*([^<]*enschede[^<]*)/i)
                   || block.match(/<h[23][^>]*>\s*([^<]+)/i);

  // Price
  const priceMatch = block.match(/(?:€|&euro;)\s*([\d.,]+)/)
                   || block.match(/class="[^"]*price[^"]*"[^>]*>\s*([^<]+)/i);

  const roomsMatch = block.match(/(\d+)\s*(?:kamer|slaapkamer)/i);
  const areaMatch = block.match(/(\d+)\s*m[²2]/);

  if (urlMatch && titleMatch) {
    const priceText = priceMatch ? priceMatch[1].trim() : 'Prijs onbekend';
    const priceClean = priceText.replace(/[^\d.,]/g, '').replace(/\./g, '').replace(',', '.');
    const priceNum = parseInt(priceClean) || 0;
    const rooms = roomsMatch ? parseInt(roomsMatch[1]) : null;

    // Filter: price range and minimum rooms
    if ((priceNum === 0 || (priceNum >= 900 && priceNum <= 1600)) && (rooms === null || rooms >= 3)) {
      const url = urlMatch[1].startsWith('http') ? urlMatch[1] : 'https://www.huurwoningen.nl' + urlMatch[1];
      results.push({
        json: {
          bron: 'Huurwoningen.nl',
          titel: titleMatch[1].trim(),
          prijs: '€ ' + priceText,
          prijsNumeriek: priceNum,
          kamers: rooms,
          oppervlakte: areaMatch ? areaMatch[1] + ' m²' : null,
          url: url,
          scraped: new Date().toISOString()
        }
      });
    }
  }
}

if (results.length === 0) {
  return [{ json: { bron: 'Huurwoningen.nl', fout: 'Geen woningen gevonden - site structuur mogelijk gewijzigd', scraped: new Date().toISOString() } }];
}

// Deduplicate by URL
const seen = new Set();
return results.filter(r => {
  if (seen.has(r.json.url)) return false;
  seen.add(r.json.url);
  return true;
});

// Parse Funda.nl response
// Funda is a React SPA with heavy anti-scraping (reCAPTCHA)
// This parser tries to extract any embedded JSON state or server-rendered content
const html = $input.first().json.data || '';
const results = [];

// Check if we got blocked by captcha
if (html.includes('recaptcha') || html.includes('captcha') || html.length < 1000) {
  return [{ json: { bron: 'Funda', fout: 'Geblokkeerd door reCAPTCHA. Overweeg: (1) Funda RSS feed, (2) handmatig zoeken op funda.nl/zoeken/huur', url: 'https://www.funda.nl/zoeken/huur?selected_area=%5B%22enschede%22%5D&price=%221000-1500%22&bedrooms=%223-%22', scraped: new Date().toISOString() } }];
}

// Try to find embedded JSON data (React hydration state)
const jsonMatch = html.match(/<script[^>]*id="__NEXT_DATA__"[^>]*>([\s\S]*?)<\/script>/)
               || html.match(/<script[^>]*type="application\/json"[^>]*>([\s\S]*?)<\/script>/);

if (jsonMatch) {
  try {
    const data = JSON.parse(jsonMatch[1]);
    // Navigate the JSON structure to find listings
    // Funda's structure varies but search results are usually nested
    const findListings = (obj, depth = 0) => {
      if (depth > 10 || !obj) return [];
      if (Array.isArray(obj)) {
        const listings = [];
        for (const item of obj) {
          if (item && typeof item === 'object' && (item.address || item.street || item.priceText || item.url)) {
            listings.push(item);
          } else {
            listings.push(...findListings(item, depth + 1));
          }
        }
        return listings;
      }
      if (typeof obj === 'object') {
        for (const key of Object.keys(obj)) {
          if (['searchResults', 'listings', 'objects', 'results', 'items'].includes(key)) {
            const found = findListings(obj[key], depth + 1);
            if (found.length > 0) return found;
          }
        }
        for (const key of Object.keys(obj)) {
          const found = findListings(obj[key], depth + 1);
          if (found.length > 0) return found;
        }
      }
      return [];
    };

    const listings = findListings(data);
    for (const listing of listings) {
      const title = listing.address || listing.street || listing.title || listing.name || 'Onbekend';
      const price = listing.priceText || listing.price || listing.rentPrice || '';
      const priceClean = String(price).replace(/[^\d]/g, '');
      const priceNum = parseInt(priceClean) || 0;
      const url = listing.url || listing.link || listing.detailUrl || '';
      const fullUrl = url.startsWith('http') ? url : 'https://www.funda.nl' + url;

      if (priceNum === 0 || (priceNum >= 900 && priceNum <= 1600)) {
        results.push({
          json: {
            bron: 'Funda',
            titel: title,
            prijs: priceNum > 0 ? '€ ' + priceNum : price,
            prijsNumeriek: priceNum,
            kamers: listing.bedrooms || listing.rooms || listing.numberOfBedrooms || null,
            oppervlakte: listing.area || listing.livingArea ? (listing.area || listing.livingArea) + ' m²' : null,
            url: fullUrl,
            scraped: new Date().toISOString()
          }
        });
      }
    }
  } catch (e) {
    // JSON parse failed
  }
}

// Fallback: try regex on raw HTML for any visible listing data
if (results.length === 0) {
  // Try to find listing links and data in rendered HTML
  const linkPattern = /href="(\/huur\/enschede[^"]+)"/g;
  let match;
  while ((match = linkPattern.exec(html)) !== null) {
    const url = 'https://www.funda.nl' + match[1];
    // Try to extract nearby text
    const context = html.substring(Math.max(0, match.index - 500), match.index + 500);
    const priceInContext = context.match(/(?:€|&euro;)\s*([\d.,]+)/);
    const titleInContext = context.match(/<[^>]*>([^<]*(?:straat|weg|laan|plein|dijk|singel|kade|gracht|markt|hof|park)[^<]*)</i);

    results.push({
      json: {
        bron: 'Funda',
        titel: titleInContext ? titleInContext[1].trim() : 'Zie link',
        prijs: priceInContext ? '€ ' + priceInContext[1] : 'Zie link',
        prijsNumeriek: priceInContext ? parseInt(priceInContext[1].replace(/[^\d]/g, '')) : 0,
        kamers: null,
        oppervlakte: null,
        url: url,
        scraped: new Date().toISOString()
      }
    });
  }
}

if (results.length === 0) {
  return [{ json: { bron: 'Funda', fout: 'Geen data - waarschijnlijk geblokkeerd door reCAPTCHA. Gebruik de directe link om handmatig te zoeken.', url: 'https://www.funda.nl/zoeken/huur?selected_area=%5B%22enschede%22%5D&price=%221000-1500%22&bedrooms=%223-%22', scraped: new Date().toISOString() } }];
}

return results;

// Parse Kamernet.nl (Next.js)
// Kamernet embeds listing data in __NEXT_DATA__ JSON
const html = $input.first().json.data || '';
const results = [];

if (!html || html.length < 500) {
  return [{ json: { bron: 'Kamernet', fout: 'Geen response ontvangen', scraped: new Date().toISOString() } }];
}

// Extract __NEXT_DATA__ JSON from Next.js hydration
const nextDataMatch = html.match(/<script\s+id="__NEXT_DATA__"[^>]*>([\s\S]*?)<\/script>/);

if (nextDataMatch) {
  try {
    const nextData = JSON.parse(nextDataMatch[1]);

    // Navigate to find listings in the props
    const findInProps = (obj, depth = 0) => {
      if (depth > 12 || !obj) return [];
      if (Array.isArray(obj)) {
        // Check if this array contains listing-like objects
        const hasListings = obj.some(item => 
          item && typeof item === 'object' && 
          (item.rent || item.price || item.monthlyRent || item.address || item.city)
        );
        if (hasListings) return obj;
        // Recurse into array items
        for (const item of obj) {
          const found = findInProps(item, depth + 1);
          if (found.length > 0) return found;
        }
        return [];
      }
      if (typeof obj === 'object') {
        for (const [key, val] of Object.entries(obj)) {
          if (['listings', 'properties', 'results', 'items', 'rooms', 'searchResults'].includes(key)) {
            const found = findInProps(val, depth + 1);
            if (found.length > 0) return found;
          }
        }
        for (const [key, val] of Object.entries(obj)) {
          const found = findInProps(val, depth + 1);
          if (found.length > 0) return found;
        }
      }
      return [];
    };

    const listings = findInProps(nextData.props || nextData);

    for (const listing of listings) {
      const title = listing.title || listing.address || listing.street || listing.name || 'Onbekend';
      const rent = listing.rent || listing.price || listing.monthlyRent || listing.totalRent || 0;
      const rentNum = typeof rent === 'number' ? rent : parseInt(String(rent).replace(/[^\d]/g, '')) || 0;
      const city = listing.city || listing.location || '';

      // Filter for Enschede and price range
      const isEnschede = !city || String(city).toLowerCase().includes('enschede');
      const inPriceRange = rentNum === 0 || (rentNum >= 900 && rentNum <= 1600);

      if (isEnschede && inPriceRange) {
        const slug = listing.slug || listing.id || '';
        const url = listing.url || (slug ? 'https://kamernet.nl/en/for-rent/property-enschede/' + slug : 'https://kamernet.nl');

        results.push({
          json: {
            bron: 'Kamernet',
            titel: title,
            prijs: '€ ' + rentNum,
            prijsNumeriek: rentNum,
            kamers: listing.bedrooms || listing.rooms || listing.numberOfRooms || null,
            oppervlakte: listing.size || listing.area || listing.surface ? (listing.size || listing.area || listing.surface) + ' m²' : null,
            url: url,
            scraped: new Date().toISOString()
          }
        });
      }
    }
  } catch (e) {
    return [{ json: { bron: 'Kamernet', fout: 'JSON parsing mislukt: ' + e.message, scraped: new Date().toISOString() } }];
  }
}

if (results.length === 0) {
  // Fallback: try to find any listing URLs in the HTML
  const urlPattern = /href="(\/(?:en\/)?for-rent\/property-enschede[^"]*)"/g;
  let match;
  while ((match = urlPattern.exec(html)) !== null) {
    results.push({
      json: {
        bron: 'Kamernet',
        titel: 'Zie link',
        prijs: 'Zie link',
        prijsNumeriek: 0,
        kamers: null,
        oppervlakte: null,
        url: 'https://kamernet.nl' + match[1],
        scraped: new Date().toISOString()
      }
    });
  }
}

if (results.length === 0) {
  return [{ json: { bron: 'Kamernet', fout: 'Geen geschikte woningen gevonden', scraped: new Date().toISOString() } }];
}

return results;

// Deduplicate results and build final overview
const items = $input.all();
const listings = [];
const errors = [];
const seenUrls = new Set();
const seenTitles = new Set();

for (const item of items) {
  const d = item.json;

  // Collect errors/warnings separately
  if (d.fout) {
    errors.push(d);
    continue;
  }

  // Skip if no URL or already seen
  if (!d.url || seenUrls.has(d.url)) continue;

  // Also dedupe by title (address) to catch cross-site duplicates
  const titleKey = d.titel ? d.titel.toLowerCase().replace(/[^a-z0-9]/g, '') : '';
  if (titleKey && titleKey !== 'zielink' && seenTitles.has(titleKey)) {
    continue;
  }

  seenUrls.add(d.url);
  if (titleKey) seenTitles.add(titleKey);
  listings.push(d);
}

// Sort by price (lowest first)
listings.sort((a, b) => (a.prijsNumeriek || 9999) - (b.prijsNumeriek || 9999));

// Build HTML email body
let emailHtml = '<h2>🏠 Huurwoningen Enschede — Dagelijks Overzicht</h2>';
emailHtml += `<p>Zoekcriteria: <strong>Enschede</strong> | <strong>3+ slaapkamers</strong> | <strong>€1.000 - €1.500/maand</strong></p>`;
emailHtml += `<p>Gevonden: <strong>${listings.length} woning(en)</strong> op ${new Date().toLocaleDateString('nl-NL')}</p>`;

if (listings.length > 0) {
  emailHtml += '<table style="border-collapse:collapse;width:100%;font-family:Arial,sans-serif;">';
  emailHtml += '<tr style="background:#2c3e50;color:white;">';
  emailHtml += '<th style="padding:10px;text-align:left;">Adres</th>';
  emailHtml += '<th style="padding:10px;text-align:left;">Prijs</th>';
  emailHtml += '<th style="padding:10px;text-align:left;">Kamers</th>';
  emailHtml += '<th style="padding:10px;text-align:left;">Oppervlakte</th>';
  emailHtml += '<th style="padding:10px;text-align:left;">Bron</th>';
  emailHtml += '<th style="padding:10px;text-align:left;">Link</th>';
  emailHtml += '</tr>';

  listings.forEach((l, i) => {
    const bg = i % 2 === 0 ? '#f8f9fa' : '#ffffff';
    emailHtml += `<tr style="background:${bg};">`;
    emailHtml += `<td style="padding:8px;border-bottom:1px solid #ddd;">${l.titel}</td>`;
    emailHtml += `<td style="padding:8px;border-bottom:1px solid #ddd;font-weight:bold;">${l.prijs}</td>`;
    emailHtml += `<td style="padding:8px;border-bottom:1px solid #ddd;">${l.kamers || '-'}</td>`;
    emailHtml += `<td style="padding:8px;border-bottom:1px solid #ddd;">${l.oppervlakte || '-'}</td>`;
    emailHtml += `<td style="padding:8px;border-bottom:1px solid #ddd;">${l.bron}</td>`;
    emailHtml += `<td style="padding:8px;border-bottom:1px solid #ddd;"><a href="${l.url}" style="color:#3498db;">Bekijk →</a></td>`;
    emailHtml += '</tr>';
  });
  emailHtml += '</table>';
} else {
  emailHtml += '<p style="color:#e74c3c;">Geen woningen gevonden die aan de criteria voldoen.</p>';
}

// Add errors/warnings
if (errors.length > 0) {
  emailHtml += '<br><h3>⚠️ Waarschuwingen</h3><ul>';
  for (const err of errors) {
    emailHtml += `<li><strong>${err.bron}:</strong> ${err.fout}`;
    if (err.url) emailHtml += ` — <a href="${err.url}">Handmatig zoeken</a>`;
    emailHtml += '</li>';
  }
  emailHtml += '</ul>';
}

// Add direct search links for manual fallback
emailHtml += '<br><h3>🔗 Directe zoeklinks</h3><ul>';
emailHtml += '<li><a href="https://www.pararius.nl/huurwoningen/enschede/1000-1500/3-slaapkamers">Pararius.nl — Enschede huurwoningen</a></li>';
emailHtml += '<li><a href="https://www.funda.nl/zoeken/huur?selected_area=%5B%22enschede%22%5D&price=%221000-1500%22&bedrooms=%223-%22">Funda.nl — Enschede huur</a></li>';
emailHtml += '<li><a href="https://www.huurwoningen.nl/in/enschede/">Huurwoningen.nl — Enschede</a></li>';
emailHtml += '<li><a href="https://kamernet.nl/en/for-rent/properties-enschede?minRent=1000&maxRent=1500">Kamernet.nl — Enschede</a></li>';
emailHtml += '<li><a href="https://www.jaap.nl/huur/overijssel/enschede">Jaap.nl — Enschede huur</a></li>';
emailHtml += '</ul>';

emailHtml += `<p style="color:#999;font-size:12px;">Gegenereerd op ${new Date().toLocaleString('nl-NL')} door n8n Huurwoning Scraper</p>`;

// Return both structured data and HTML for email
const output = [{
  json: {
    aantalWoningen: listings.length,
    aantalFouten: errors.length,
    emailOnderwerp: `🏠 ${listings.length} huurwoning(en) gevonden in Enschede — ${new Date().toLocaleDateString('nl-NL')}`,
    emailHtml: emailHtml,
    woningen: listings,
    fouten: errors
  }
}];

return output;
